mapper.select:
select distinct objectid as objectId, objectName, tableName, tableId, objectState, dataSourceCode, sjzybq1, sjzybq2, sjzybq3, sjzybq4, sjzybq5, sjzybq6, trim(dataSourceCh) as dataSourceCh, createTime, case when creator is null then '' else trim(creator) end as creator, case when updater is null then '' else trim(updater) end as updater, updateTime, dataOrganizationClassify, dataSourceClassify from (select distinct o.objectid, c.sjxjbm as tableId, c.sjxjzwmc as objectName, c.tablename as tableName, c.sjzybq1, c.sjzybq2, c.sjzybq3, c.sjzybq4, c.sjzybq5, c.sjzybq6, case when c.objectstate is null then -1 else c.objectstate end as objectState, o.data_source as dataSourceCode, s.valtext as dataSourceCh, case when o.createtime is null then '' else to_char(o.createtime, 'yyyy-mm-dd HH24:mi:ss') end as createTime, o.creator as creator, o.updater as updater, case when o.updatetime is null then '' else to_char(o.updatetime, 'yyyy-mm-dd HH24:mi:ss') end as updateTime, case when c.secondaryorganizationch is null or c.secondaryorganizationch = '' then c.primaryorganizationch else c.primaryorganizationch || '->' || c.firstorganizationch || '->' || c.secondaryorganizationch end as dataOrganizationClassify, case when c.secondarydatasourcech is null then c.primarydatasourcech else c.primarydatasourcech || '->' || c.secondarydatasourcech end as dataSourceClassify from classify_interface_all_date c right join (select * from synlte.object where deleted = 0 and upper(relate_tablename) = 'OBJECTFIELD') o on upper(c.sjxjbm) = upper(o.tableid) left join (select distinct valtext, valvalue from synlte.fieldcodeval where codeid = 'JZCODE0024') s on upper(o.data_source) = upper(s.valvalue)) x
and (upper(x.objectname) like upper('%${summaryQueryParams.searchCode}%') or upper(x.tablename) like upper('%${summaryQueryParams.searchCode}%') or upper(x.tableid) like upper('%${summaryQueryParams.searchCode}%'))
and x.dataorganizationclassify in
#{item}
and x.datasourceclassify in
#{item}
and x.sjzybq1 in
#{item}
and x.sjzybq2 in
#{item}
and x.sjzybq3 in
#{item}
and x.sjzybq4 in
#{item}
and x.sjzybq5 in
#{item}
and x.sjzybq6 in
#{item}
and x.objectstate in
#{item}
and (0, x.objectid) in
(0, #{item})
order by ${summaryQueryParams.sort}
${summaryQueryParams.sortOrder}
